const int N = 4e6 + 10;
int cnt[N];
void solve(int CASE)
{
	int n, m, s, t; cin >> n >> m >> s >> t;

	///////// 大区间离散化成小区间 /////////
	var b = vector<int>();
	var p = vector<pii>(m + 1);
	fa(i, 1, m) {
		int _; cin >> _;
		cin >> p[i].px >> p[i].py;
		b.pb(p[i].px), b.pb(p[i].py);
		b.pb(p[i].px - 1), b.pb(p[i].py + 1); // 重点！保证区间与区间的空隙区间保留
	}

	sort(all(b));
	b.erase(unique(all(b)), b.end());
	int len = b.size();
	var find = [&](int value)->int {
		return upper_bound(all(b), value) - b.begin() - 1;
		};
	//var cnt = vector<int>(100);

	fa(i, 1, m) {
		int l = find(p[i].px), r = find(p[i].py);
		cnt[l]++, cnt[r + 1]--;
	}
	fa(i, 1, len - 1)cnt[i] += cnt[i - 1];
	ll ans = 1;
	fa(i, 0, len - 1) {
		int l = b[i - 1] + 1, r = b[i];
		if (i == 0)l = s;
		if (i == len - 1)r = t;
		ans = ans * Math::fastPow(n - cnt[i], r - l + 1ll, mod) % mod;
	}
	cout << ans << endl;

